
import Form from './components/Form';
import Input from './components/Input';
import InputPassword from './components/InputPassword';
import Label from './components/Label';

export default function LoginPage() {
  return (
    <section className="flex h-screen flex-col items-center justify-center text-white">
      <h1 className="py-4">Login administrador</h1>
      <Form>
        <Label htmlFor="email">Email:</Label>
        <Input
          name="email"
          type="email"
          autoComplete="email"
          autoFocus={true}
        />
        <Label htmlFor="password">Senha:</Label>
        <InputPassword />
        {/* <Button
          variant={'ghost'}
          className="mt-4 rounded bg-dark-gray px-4 py-2 font-semibold transition-colors duration-200"
        >
          Entrar
        </Button> */}
      </Form>
    </section>
  );
}
